import { catchAsync } from '../utils/catchAsync.js';
import AppError from '../utils/AppError.js';
import * as propertyService from '../services/property.service.js';
import { getAllProperties } from '../services/property.service.js';
import { User } from '../models/User.js';

export const createProperty = catchAsync(async (req, res, next) => {
  // 1. Security Check
  if (!req.user.agencyId) {
    return next(new AppError('Unauthorized: You must be registered under a verified Real Estate Agency.', 403));
  }

  // 2. Extract the live URLs generated by the upload middleware
  let extractedMediaUrls = [];
  if (req.files && req.files.length > 0) {
    // multer-storage-cloudinary stores the secure URL exactly here
    extractedMediaUrls = req.files.map((file) => file.path);
  }

  // 3. Merge the live URLs with your strictly validated text payload
  const finalPayload = {
    ...req.validated.body,
    mediaUrls: extractedMediaUrls,
  };

  // 4. Pass the complete package to your service engine
  const newProperty = await propertyService.createListing(
    finalPayload, 
    req.user.agencyId
  );

  // 5. Return the successful response
  res.status(201).json({
    status: 'success',
    data: {
      property: newProperty,
    },
  });
});

// We will also wire up the search controller so it's ready!
export const getNearbyProperties = catchAsync(async (req, res, next) => {
  const { lng, lat, distance } = req.query;

  if (!lng || !lat) {
    return next(new AppError('Please provide both longitude (lng) and latitude (lat) query parameters.', 400));
  }

  const properties = await propertyService.findPropertiesNearMe(
    parseFloat(lng),
    parseFloat(lat),
    distance ? parseInt(distance) : 5000 // Default to 5km radius
  );

  res.status(200).json({
    status: 'success',
    results: properties.length,
    data: {
      properties,
    },
  });
});


export const getProperties = catchAsync(async (req, res, next) => {
  const result = await propertyService.getAllProperties(req.query);

  res.status(200).json({
    status: 'success',
    results: result.properties.length,
    pagination: {
      total: result.total,
      page: result.page,
      limit: result.limit,
      totalPages: result.totalPages,
    },
    data: {
      properties: result.properties,
    },
  });
});

export const searchProperties = catchAsync(async (req, res, next) => {
  // 1. Clone the incoming frontend query parameters
  const frontendQuery = { ...req.query };
  const standardizedQuery = {};

  // 2. Translate Front-End Search Console inputs to Schema fields
  
  // Map the text location input (e.g., "Ikoyi") to your locality field
  if (frontendQuery.location && frontendQuery.location.trim() !== '') {
    standardizedQuery.locality = frontendQuery.location.trim();
  }

  // 🎯 THE NEW PREMIUM PRICING ENGINE
  if (frontendQuery.minBudget || frontendQuery.maxBudget) {
    
    // 🚨 Changed from .price to .pricePerAnnum to match the MongoDB document
    standardizedQuery.pricePerAnnum = {}; 
    
    // Inject Greater-Than-Or-Equal-To (minBudget)
    if (frontendQuery.minBudget && frontendQuery.minBudget !== 'any') {
      standardizedQuery.pricePerAnnum.gte = parseInt(frontendQuery.minBudget, 10);
    }
    
    // Inject Less-Than-Or-Equal-To (maxBudget)
    if (frontendQuery.maxBudget && frontendQuery.maxBudget !== 'any') {
      standardizedQuery.pricePerAnnum.lte = parseInt(frontendQuery.maxBudget, 10);
    }
  }
  // 3. Pass through any native system fields directly if provided
  if (frontendQuery.sort) standardizedQuery.sort = frontendQuery.sort;
  if (frontendQuery.page) standardizedQuery.page = frontendQuery.page;
  if (frontendQuery.limit) standardizedQuery.limit = frontendQuery.limit;

  // 4. Fire the pre-existing high-performance layout engine
  const searchResults = await getAllProperties(standardizedQuery);

  // 5. Dispatch the premium API response
  res.status(200).json({
    status: 'success',
    results: searchResults.properties.length,
    pagination: {
      total: searchResults.total,
      page: searchResults.page,
      limit: searchResults.limit,
      totalPages: searchResults.totalPages,
    },
    data: {
      properties: searchResults.properties,
    },
  });
});
export const updateProperty = catchAsync(async (req, res, next) => {
  const propertyId = req.params.id;
  const agencyId = req.user.agencyId; // Extracted safely from auth middleware

  const updatedProperty = await propertyService.updateProperty(
    propertyId, 
    agencyId, 
    req.body
  );

  // If the ID doesn't exist OR agencyId mismatched, return a clean 404/unauthorized message
  if (!updatedProperty) {
    return next(new Error('Property not found or you lack administrative authorization to modify it'));
  }

  res.status(200).json({
    status: 'success',
    data: {
      property: updatedProperty,
    },
  });
});

export const deleteProperty = catchAsync(async (req, res, next) => {
  const propertyId = req.params.id;
  const agencyId = req.user.agencyId;

  const deletedProperty = await propertyService.deleteProperty(propertyId, agencyId);

  if (!deletedProperty) {
    return next(new Error('Property not found or you lack administrative authorization to purge it'));
  }

  // 204 status signifies standard successful resource destruction with no payload content returned
  res.status(204).json({
    status: 'success',
    data: null,
  });
});

export const togglePropertySave = async (req, res) => {
  try {
    const propertyId = req.params.id;
    const userId = req.user.id; 

    // 1. Locate the authenticated user profile document using your User model inside the property controller
    const user = await User.findById(userId);
    if (!user) {
      return res.status(404).json({ success: false, message: "Profile session missing." });
    }

    // 2. Toggle item logic: Check if the property already exists in the collection array
    const isSaved = user.savedCollections.includes(propertyId);
    
    if (isSaved) {
      // Pull/Remove if already saved
      user.savedCollections.pull(propertyId);
    } else {
      // Push/Add if it's a new bookmark addition
      user.savedCollections.push(propertyId);
    }

    await user.save();
    
    // 3. Return the fully refreshed user record back to your Zustand storage ecosystem
    // Fully populate it if you want to immediately parse the listing components inside the dashboard
    const populatedUser = await user.populate('savedCollections');

    return res.status(200).json({
      success: true,
      message: isSaved ? "Removed from list" : "Added to list",
      user: populatedUser
    });

  } catch (error) {
    return res.status(500).json({ success: false, message: error.message });
  }
};